"use client"

import { useState, useEffect, useRef } from "react"
import { Search, Building2, User, Users, Loader2, X } from "lucide-react"
import { Input } from "@/components/ui/input"
import { globalSearch, type SearchResult } from "@/app/actions/search"
import { useRouter } from "next/navigation"
import Link from "next/link"

export function GlobalSearch() {
    const [query, setQuery] = useState("")
    const [results, setResults] = useState<SearchResult[]>([])
    const [isLoading, setIsLoading] = useState(false)
    const [isOpen, setIsOpen] = useState(false)
    const containerRef = useRef<HTMLDivElement>(null)
    const router = useRouter()

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
                setIsOpen(false)
            }
        }
        document.addEventListener("mousedown", handleClickOutside)
        return () => document.removeEventListener("mousedown", handleClickOutside)
    }, [])

    useEffect(() => {
        const delayDebounceFn = setTimeout(async () => {
            if (query.length >= 2) {
                setIsLoading(true)
                try {
                    const searchResults = await globalSearch(query)
                    setResults(searchResults)
                    setIsOpen(true)
                } catch (error) {
                    console.error("Search error:", error)
                } finally {
                    setIsLoading(false)
                }
            } else {
                setResults([])
                setIsOpen(false)
            }
        }, 300)

        return () => clearTimeout(delayDebounceFn)
    }, [query])

    const handleSelect = (url: string) => {
        setIsOpen(false)
        setQuery("")
        router.push(url)
    }

    return (
        <div className="relative w-64 lg:w-96 group" ref={containerRef}>
            <div className="relative">
                <Search className={`absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 transition-colors ${isOpen ? 'text-blue-500' : 'text-gray-400 group-hover:text-blue-500'}`} />
                <Input
                    placeholder="Buscar propiedades, clientes..."
                    className="h-10 w-full rounded-full bg-gray-50 border-transparent pl-10 pr-10 focus:bg-white focus:border-blue-100 transition-all font-medium text-sm shadow-sm"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    onFocus={() => query.length >= 2 && setIsOpen(true)}
                />
                {isLoading ? (
                    <Loader2 className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-blue-500 animate-spin" />
                ) : query && (
                    <button
                        onClick={() => setQuery("")}
                        className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400 hover:text-gray-600"
                    >
                        <X className="h-4 w-4" />
                    </button>
                )}
            </div>

            {isOpen && (
                <div className="absolute top-full left-0 right-0 mt-2 bg-white rounded-3xl shadow-2xl border border-gray-100 overflow-hidden z-50 animate-in fade-in slide-in-from-top-2 duration-200">
                    <div className="max-h-[400px] overflow-y-auto p-2">
                        {results.length > 0 ? (
                            <div className="space-y-4 p-2">
                                {(['property', 'lead', 'agent'] as const).map(type => {
                                    const typeResults = results.filter(r => r.type === type)
                                    if (typeResults.length === 0) return null

                                    return (
                                        <div key={type}>
                                            <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-3 mb-2">
                                                {type === 'property' ? 'Propiedades' : type === 'lead' ? 'Clientes' : 'Equipo'}
                                            </h3>
                                            <div className="space-y-1">
                                                {typeResults.map(result => (
                                                    <button
                                                        key={result.id}
                                                        onClick={() => handleSelect(result.url)}
                                                        className="w-full flex items-center gap-3 p-3 rounded-2xl hover:bg-blue-50 transition-colors text-left group/item"
                                                    >
                                                        <div className={`h-10 w-10 rounded-xl flex items-center justify-center shrink-0 shadow-sm ${type === 'property' ? 'bg-amber-50 text-amber-600' :
                                                                type === 'lead' ? 'bg-blue-50 text-blue-600' :
                                                                    'bg-purple-50 text-purple-600'
                                                            }`}>
                                                            {type === 'property' ? <Building2 className="h-5 w-5" /> :
                                                                type === 'lead' ? <Users className="h-5 w-5" /> :
                                                                    <User className="h-5 w-5" />}
                                                        </div>
                                                        <div className="flex-1 min-w-0">
                                                            <p className="text-sm font-bold text-gray-900 truncate group-hover/item:text-blue-700">
                                                                {result.title}
                                                            </p>
                                                            {result.subtitle && (
                                                                <p className="text-xs text-gray-500 truncate">
                                                                    {result.subtitle}
                                                                </p>
                                                            )}
                                                        </div>
                                                    </button>
                                                ))}
                                            </div>
                                        </div>
                                    )
                                })}
                            </div>
                        ) : (
                            <div className="p-8 text-center">
                                <p className="text-sm font-bold text-gray-800">No se encontraron resultados</p>
                                <p className="text-xs text-gray-400 mt-1">Intenta con otra palabra clave</p>
                            </div>
                        )}
                    </div>
                    <div className="bg-gray-50 p-3 text-center border-t border-gray-100">
                        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                            Presiona ESC para cerrar
                        </p>
                    </div>
                </div>
            )}
        </div>
    )
}
